<html>
<head>
	<meta http-equiv="Content-Type" content="text/html; charset=UTF-8">
	<meta name="viewport" content="width=device-width, initial-scale=1">
	<title>Payment Page</title>
	<link rel="stylesheet" href="/assets/css/bharatpegateway.css">
	<script src="http://ajax.googleapis.com/ajax/libs/jquery/1.9.1/jquery.min.js"></script>
	<script>
		var cs = "";
		//var mm=2;
		var mm = 4;
		var ss = 59;
		$(document).ready(function () {
			var inFormOrLink = false;
			function ConfirmLeave() {

				var prevKey = "";
				$(document).keydown(function (e) {
					if (e.key == "F5") {
						window.onbeforeunload = null;
					}

				});
			}

			$('body').on('click', function () {
				inFormOrLink = true;
			});
			$('a').on('click', function () {
				inFormOrLink = true;
			});
			$('form').on('submit', function () {
				inFormOrLink = true;
			});
		});
		function verifyUPIstatus() {
// 			setTimeout(function () {
				$.ajax({
					datatype: "json",
					type: "post",
					contentType: "application/json",
					url: "/payverify.php",
					success: function (response) {
						var obj = JSON.parse(response);
						if (obj.status == "success") {
							cs = "success";
						}
						else if (obj.status == "Rejected") {
							cs = "Rejected";
						}
						else if (obj.status == "sessionExpire") {
							cs = "sessionExpire";
						}
						else {
							verifyUPIstatus();
						}
					}
				});
// 			}, 10000);
		}
		function timerFun() {
			jQuery("#timer").text(05 + ":" + 00);
			$('#progressImg').show();
			startTimer();
		}

		function startTimer() {
			var presentTime = document.getElementById('timer').innerHTML;
			var timeArray = presentTime.split(/[:]+/);
			var m = timeArray[0];

			var s = checkSecond((timeArray[1] - 1));
			ss = s;
			if (s == 59) { m = m - 1 }
			mm = m;
			if (cs == "success" || cs == "Rejected") {
				document.upiPayform.action = "/response.php";

				document.upiPayform.method = 'POST';
				document.upiPayform.submit();
				return false;
			}
			else if (cs == "sessionExpire") {
				document.forms["sessionExpire"].submit();
				return false;
			}
			else if (m < 0) {
				/* alert('timer completed');   */

				document.upiPayform.action = "/response.php";


				/* document.upiPayform.action = "/upiPay"; */
				document.upiPayform.method = 'POST';
				document.upiPayform.submit();
				//document.getElementById("upiFormID").submit();
				return false;
			}

			document.getElementById('timer').innerHTML =
				m + ":" + s;
			setTimeout(startTimer, 1000);
		}

		function checkSecond(sec) {
			if (sec < 10 && sec >= 0) { sec = "0" + sec }; // add zero in front of numbers < 10
			if (sec < 0) { sec = "59" };
			return sec;
		}
	</script>
</head>

